# -*- coding: utf-8 -*-
import re
import os
import sys

BASE = os.path.join(os.path.dirname(os.path.abspath(__file__)), '..')
path = os.path.join(BASE, 'app', 'era-lore.js')
with open(path, 'r', encoding='utf-8') as f:
    content = f.read()

rewrites = [
    ('対位法の黄金期', 'J.S.バッハ（1685-1750）はライプツィヒ・聖トーマス教会の音楽監督として毎週の教会カンタータを書き続け、対位法の芸術を極限まで磨いた。1722年の「平均律クラヴィーア曲集 第1巻」、1747年フリードリヒ大王に献呈された「音楽の捧げもの」、死の前年の「フーガの技法」——バッハの晩年は対位法の百科事典と言える。同時代のヘンデル（1685-1759）はロンドンでオラトリオの王となり、1742年ダブリンで初演された「メサイア」の「ハレルヤ・コーラス」は現在も世界中で歌い継がれる。', ['bach', 'handel']),
    ('オペラの誕生', '1607年、マントヴァ宮廷でモンテヴェルディ（1567-1643）の「オルフェオ」が上演された。ギリシャ神話を題材に音楽と劇を融合させた最初期の本格オペラ。やがてオペラはヴェネツィアで公開劇場文化を生み、ヘンデルの時代にはロンドンのコヴェント・ガーデンを席巻。バッハはオペラを書かなかったが、代わりに「マタイ受難曲」（1727）で劇的な宗教音楽を完成させた。', ['handel', 'bach']),
    ('ソナタ形式の完成', '提示部→展開部→再現部という3部構造のソナタ形式は、ハイドン（1732-1809）によって原型が作られ、モーツァルト（1756-1791）で洗練され、ベートーヴェン（1770-1827）で劇化された。ベートーヴェンの交響曲第5番「運命」（1808）では「ジャジャジャジャーン」という4音動機が全楽章を貫き、形式そのものがドラマになった。', ['haydn', 'mozart', 'beethoven']),
    ('交響曲の隆盛', 'ハイドンは1761年からエステルハージ家に30年間仕え、100曲以上の交響曲を生み「交響曲の父」と呼ばれた。モーツァルトは1788年夏のわずか数週間で最後の3大交響曲（第39・40・41番「ジュピター」）を書き上げ、ベートーヴェンは1824年に交響曲第9番で合唱を導入、「歓喜の歌」で人類の普遍を謳った。', ['haydn', 'mozart', 'beethoven']),
    ('歌曲の芸術', '18歳のシューベルト（1797-1828）がゲーテの詩に作曲した「魔王」（1815）はドイツ・リートの金字塔。彼は31年の短い生涯に600曲以上の歌曲を残し、代表作「冬の旅」（1827）は24曲の連作で失恋の放浪を綴った。1840年、シューマン（1810-1856）はクララとの結婚の年に140曲以上の歌曲を一気に書き、「歌の年」と呼ばれた。', ['schubert', 'schumann']),
    ('ピアノの詩人たち', 'ショパン（1810-1849）はピアノのためだけに作曲し続けた希有な作曲家。パリのサロンで21曲の夜想曲、27曲の練習曲、4曲のバラードを書いた。1836年からジョルジュ・サンドとの10年のノアン滞在が創作の黄金期。シューマンの「クライスレリアーナ」（1838）、メンデルスゾーンの「無言歌集」——ピアノは作曲家の内面を語る親密な楽器となった。', ['chopin', 'schumann']),
    ('楽劇という総合芸術', 'ワーグナー（1813-1883）は音楽・詩・演出・舞台美術を一人で統括する「楽劇（ムジークドラマ）」を提唱。26年をかけて完成した4部作「ニーベルングの指環」は1876年、バイロイト祝祭劇場のこけら落としで初演された。ライトモティーフ技法（人物や概念に固有の動機を与える）は後の映画音楽にまで影響を及ぼしている。', ['wagner']),
    ('交響曲の巨大化', 'ブルックナー（1824-1896）の交響曲第8番は90分を超える長大さ。マーラー（1860-1911）の第8番「千人の交響曲」は演奏者約1000人を要する未曾有の規模。ブラームス（1833-1897）は「ベートーヴェンの影」に怯えて第1番完成に21年を費やしたが、古典的均整を守りつつロマン派の情熱を湛えた。', ['brahms']),
    ('色彩と揺らぎ', 'ドビュッシー（1862-1918）は機能和声の呪縛から音楽を解放した。「牧神の午後への前奏曲」（1894）、ピアノ曲「月の光」（1905年出版）、交響詩「海」（1905、北斎「神奈川沖浪裏」を楽譜表紙に）——全音音階や5度和音で輪郭を溶かす。ラヴェル（1875-1937）は「ボレロ」（1928）で単一旋律の17分反復という奇跡を見せた。', []),
    ('東洋への憧憬', '1889年パリ万博でドビュッシーがジャワ島のガムラン音楽を聴き、深い衝撃を受けた。以後、5音音階や非機能的な響きを積極的に取り入れる。ピアノ曲「塔」「魚の中の金魚」には東洋的意匠が明示的に現れる。ラヴェルも「マ・メール・ロワ」で中国やインドネシアのモチーフを用いた。', []),
    ('調性の解体', 'シェーンベルク（1874-1951）はピアノ曲Op.11（1909）で完全に調性を離脱、「月に憑かれたピエロ」（1912）で語り歌（シュプレヒシュティンメ）を生んだ。1923年には12音を対等に扱う「十二音技法」を発明。弟子のベルク（オペラ「ヴォツェック」1925）、ヴェーベルンと共に新ウィーン楽派を形成した。', ['schoenberg']),
    ('原始主義とリズム', 'ストラヴィンスキー（1882-1971）の「春の祭典」（1913年5月29日、パリ・シャンゼリゼ劇場初演）は、ディアギレフのロシア・バレエ団、ニジンスキー振付で上演されるや暴動が起きた。原始的リズム、不協和音、変拍子——20世紀音楽の転換点。作曲者はのちに新古典主義へ転じ、「プルチネッラ」「兵士の物語」など多様な作風を展開した。', ['stravinsky']),
    ('東洋と西洋の出会い', '武満徹（1930-1996）は「ノヴェンバー・ステップス」（1967）で琵琶・尺八とオーケストラを対峙させ、雅楽の「間」の美学を現代音楽に持ち込んだ。坂本龍一（1952-2023）はYMOの電子音響から「戦場のメリークリスマス」（1983）、「ラストエンペラー」（1987）のアカデミー賞受賞まで、ジャンルを越境した。', ['takemitsu', 'ryuichi_sakamoto']),
    ('ミニマル・映画音楽', 'ライヒ（1936-）の「ピアノ・フェイズ」（1967）やグラス（1937-）のオペラ「浜辺のアインシュタイン」（1976）から始まるミニマル音楽は、反復と位相ずれで時間の感覚を変質させる。久石譲（1950-）はジブリ作品——「となりのトトロ」（1988）、「千と千尋の神隠し」（2001）——で日本の心象風景を映画音楽に結晶化した。', ['hisaishi']),
    ('中国の諸子百家', '春秋戦国の乱世（紀元前770-221）、諸子百家が思想を競った。孔子（BC551-479）は魯国で「仁」と「礼」を説き、門弟3000を擁した。孟子は性善説、荀子は性悪説を唱え儒家を発展させた。老子（伝BC6世紀）は「道の道とすべきは常の道にあらず」と無為自然を説き、荘子が「胡蝶の夢」で受け継いだ。墨子は兼愛非攻、韓非子は法家を論じた。', ['confucius', 'laozi']),
    ('インドの覚醒', 'ブッダ（伝BC563-483）は釈迦族の王子ゴータマ・シッダールタとして生まれ、29歳で出家、35歳でブッダガヤの菩提樹下で悟りを開いた。以後45年間、ガンジス川流域を歩きながら四諦（苦・集・滅・道）と八正道を説いた。カーストを問わず誰にでも教えを説いたことがバラモン教の権威への革命だった。', ['buddha']),
    ('ソクラテスの問答', 'ソクラテス（BC470頃-399）は石工の父と助産婦の母のもと生まれ、アテナイのアゴラで市民と対話を続けた。「無知の知」——自分は知らないことを知っていると認めるところから哲学が始まる。産婆術（エレンコス）で相手の矛盾を露わにする手法。紀元前399年、「青年を堕落させた」罪で死刑、毒杯を仰いで没した。弟子プラトンが対話篇で師の姿を永遠に伝えた。', ['socrates', 'plato']),
    ('イデアと形相', 'プラトン（BC427-347）はアテナイ郊外に学園アカデメイアを創設（BC387）。「国家」で哲人王の理想と「洞窟の比喩」を、「饗宴」で愛（エロース）の本質を論じた。弟子アリストテレス（BC384-322）は20年学んだ後、独立してリュケイオンを開き「逍遥学派」と呼ばれた。師のイデア論を批判し、形相と質料で世界を説明、のちアレクサンドロス大王の家庭教師ともなった。', ['plato', 'aristotle']),
    ('皇帝と奴隷の哲学', 'ストア哲学は身分を問わなかった。皇帝マルクス・アウレリウス（121-180）はゲルマン戦役の陣中で「自省録」を綴り、元奴隷エピクテトス（55頃-135頃）の「語録」と並んで現代まで読み継がれる。セネカ（BC4-AD65）は皇帝ネロの家庭教師だったが、謀反の疑いで自殺を命じられ、静かに血管を切って死を迎えた。', []),
    ('コントロールの輪', 'エピクテトスは教える。「支配できるもの（自分の判断・意志）と、支配できないもの（他者・外的事象）を分けよ」。マルクス・アウレリウスは自らに問う。「今日、私が出会うのは厚かましい人、恩知らず、傲慢な人だ——しかし彼らも理性を持つ人間である」。この二分法は現代の認知行動療法の基盤となった。', []),
    ('コギト・エルゴ・スム', 'デカルト（1596-1650）は1619年11月10日、ドナウ河畔の暖炉部屋で3つの夢を見て学問統一の使命を確信。徹底的な懐疑の果てに「疑っている私」の存在は疑えないと悟る。1637年「方法序説」で「我思う、ゆえに我あり」（コギト・エルゴ・スム）を提示。1649年スウェーデン女王クリスティーナに招かれストックホルムに赴くが、厳寒の朝5時の講義で風邪をこじらせ翌年没。', ['descartes']),
    ('汎神論の迫力', 'スピノザ（1632-1677）はアムステルダムのユダヤ人共同体で23歳のとき破門される（1656）。以後レンズ磨きで生計を立てながら思索。死後出版の「エチカ」（1677）は幾何学的方法で倫理学を記述、神と自然を同一視する汎神論を展開。当時としては異端の極みだったが、ゲーテ、アインシュタインが深く傾倒した。', ['spinoza']),
    ('社会契約と人権', 'ロック（1632-1704）は1689年「市民政府二論」で、政府は市民の同意に基づき生命・自由・財産の自然権を守るために存在すると説いた。モンテスキュー（1689-1755）は「法の精神」（1748）で三権分立を提唱。ルソー（1712-1778）は「社会契約論」（1762）で「人間は自由なものとして生まれた、しかしいたるところで鉄鎖に繋がれている」と書き、一般意志と主権在民を論じた。これらが1776年アメリカ独立宣言、1789年フランス人権宣言の礎となる。', ['john_locke', 'rousseau']),
    ('百科全書の革命', 'ディドロ（1713-1784）とダランベール（1717-1783）が編纂した「百科全書」（1751-1772）は全28巻、約7万項目。職人の技法から哲学・政治まで、あらゆる知を万人に開く試み。ヴォルテール、ルソー、モンテスキューら150人以上が執筆した。旧制度への批判を含むため発禁処分も受けたが、ヨーロッパの知識人の思考を更新し、フランス革命の地下水脈となった。', ['voltaire', 'rousseau']),
    ('コペルニクス的転回', 'カント（1724-1804）は57歳で「純粋理性批判」（1781）を発表、認識論に革命をもたらした。「認識は対象に従うのではなく、対象が認識に従う」——我々は時間・空間・カテゴリーという主観の枠組みを通してしか物を知らない。物自体（ディング・アン・ジッヒ）は不可知。1788年「実践理性批判」で道徳を、1790年「判断力批判」で美を論じ、三批判書を完成した。', ['kant']),
    ('歴史は自由を実現する', 'ヘーゲル（1770-1831）はナポレオン軍がイェーナに迫る中、1807年「精神現象学」を完成させた。世界史は「自由の意識の進歩」であり、正・反・合の弁証法で矛盾を通じて絶対精神が自己展開する。1818年ベルリン大学教授となりプロイセン国家哲学者として君臨、1831年コレラで急死。ショーペンハウアー（1788-1860）、キルケゴール（1813-1855）、マルクス（1818-1883）はいずれもヘーゲルを通過しつつ、それぞれ別の道を切り拓いた。', ['hegel', 'schopenhauer', 'kierkegaard', 'marx']),
    ('実存の問い', 'ハイデガー（1889-1976）は「存在と時間」（1927）で「現存在（人間）」の分析から存在の意味を問うた。サルトル（1905-1980）は「存在と無」（1943）でドイツ占領下のパリから「実存は本質に先立つ」「人間は自由の刑に処せられている」と宣言。カミュ（1913-1960）は「シーシュポスの神話」（1942）で「この不条理な世界でなお生きる理由はあるか」を問うた。', ['heidegger', 'sartre', 'camus']),
    ('言語と構造', 'ウィトゲンシュタイン（1889-1951）は「論理哲学論考」（1921）で「語りえぬものについては沈黙しなければならない」と結論、哲学を言語分析に還元した。後期には一転、「哲学探究」で言語ゲーム論を展開。フーコー（1926-1984）は「言葉と物」（1966）「監獄の誕生」（1975）で知と権力の構造を暴き、「人間」の概念は近代の発明にすぎないと論じた。', ['wittgenstein', 'foucault']),
    ('万能人の理想', 'レオナルド・ダ・ヴィンチ（1452-1519）は画家でありながら解剖学、工学、軍事技術、植物学を極めた。「モナ・リザ」（1503-06）、「最後の晩餐」（1498、ミラノ・サンタ・マリア・デッレ・グラツィエ教会）、5000ページを超える手稿が残る。ミケランジェロ（1475-1564）は彫刻「ダヴィデ像」（1504）、システィーナ礼拝堂の天井画（1508-12）、サン・ピエトロ大聖堂の設計。ラファエロ（1483-1520）の「アテナイの学堂」——この三人で盛期ルネサンスは頂点を極めた。', ['leonardo', 'michelangelo']),
    ('遠近法の発見', 'ブルネレスキ（1377-1446）は1420年代に線遠近法を数学的に定式化、絵画が3次元空間を獲得した。1436年にはフィレンツェ大聖堂（ドゥオーモ）の大円蓋を完成、古代ローマ以来の大ドーム建築を復活させた。画家マサッチオは「聖三位一体」（1427頃）で遠近法を最初期に応用。以後アルベルティ「絵画論」（1435）が理論化し、イタリア全土に広まった。', []),
    ('キアロスクーロ', 'カラヴァッジョ(1571-1610)は明暗法(キアロスクーロ)を極限まで突き詰めた。「聖マタイの召命」(1599-1600、ローマ・サン・ルイジ・デイ・フランチェージ教会)では暗闇の中、キリストの指だけが光の一条として射し込む。彼は乱暴者でもあり、1606年殺人を犯して逃亡、39歳で放浪の末に客死。その生々しい写実主義はベラスケス、レンブラントら後世に深い影響を与えた。', []),
    ('北方の光', 'オランダ黄金期(17世紀)、プロテスタントの市民社会では宗教画より日常が主題となった。フェルメール(1632-1675)はデルフトで約36点の小品を残し、「真珠の耳飾りの少女」(1665頃)、「牛乳を注ぐ女」で窓からの光を神聖化した。レンブラント(1606-1669)は「夜警」(1642)で市民自警団を劇化、生涯80点を超える自画像で人間の老いを掘り下げた。晩年は破産のうちに孤独死した。', ['vermeer', 'rembrandt']),
    ('版画というメディア', '浮世絵は絵師・彫師・摺師の分業体制で大量生産された「江戸のメディア」。1765年頃、鈴木春信らが多色摺木版(錦絵)を完成させた。鳥居清長の美人画、東洲斎写楽(1794-95のわずか10ヶ月活動)の役者大首絵、喜多川歌麿(1753頃-1806)の女性美、葛飾北斎(1760-1849)の「富嶽三十六景」(1831頃)、歌川広重(1797-1858)の「東海道五十三次」(1833-34)——庶民の手に届く価格で流通した。', []),
    ('ジャポニスムへ', '幕末、陶器の包み紙として欧州に流出した浮世絵が印象派画家を震撼させた。1862年ロンドン万博、1867年パリ万博で日本美術が紹介される。ゴッホは広重「大はしあたけの夕立」を模写(1887)。モネは庭に日本風の橋を架け、ドビュッシーは交響詩「海」の楽譜表紙に北斎「神奈川沖浪裏」を用いた。ジャポニスムは西洋美術の転換点となった。', ['van_gogh', 'monet']),
    ('光を描く', 'モネ(1840-1926)の「印象・日の出」(1872)が「印象派」の名の由来。アトリエから飛び出し、屋外で刻々と変わる光を捉える「外光派」の試み。1874年の第1回印象派展にはルノワール、ドガ、ピサロ、セザンヌが参加した。モネは同じ主題(積みわら、ルーアン大聖堂、睡蓮)を時刻・季節を変えて繰り返し描いた。1899年から始まる「睡蓮」連作は30年以上続いた。', ['monet']),
    ('近代都市の絵画', 'ナポレオン3世下のオスマン男爵によるパリ改造(1853-70)で誕生した近代都市が画題となった。マネ「草上の昼食」(1863、落選展でスキャンダル)、ドガのバレエの楽屋、カイユボットの「パリの通り、雨」、ルノワール「ムーラン・ド・ラ・ギャレット」(1876)——鉄道駅、オペラ座、カフェ、舞踏会。近代化する都市の光と影が絵画に書き留められた。', []),
    ('キュビスムの衝撃', 'ピカソ(1881-1973)とブラック(1882-1963)が1907年頃から始めたキュビスムは、西洋絵画500年の透視図法を破壊した。ピカソ「アヴィニヨンの娘たち」(1907)は5人の裸婦をアフリカ仮面のように描く衝撃作。対象を多視点から同時に描き、2次元の画面に3次元以上の時間性を持ち込んだ。1937年の「ゲルニカ」はスペイン内戦の空爆に抗議し、1ヶ月で完成した反戦芸術の永遠の象徴。', ['picasso']),
    ('抽象の誕生', 'カンディンスキー(1866-1944)は1910年前後、具象から完全に離れた抽象絵画を描いた最初期の画家。著書「芸術における精神的なもの」(1912)で色と形が音楽のように魂に響くと論じた。マレーヴィチの「黒い正方形」(1915)、モンドリアン(1872-1944)の格子状コンポジション、バウハウス(1919年創設)——20世紀の抽象芸術は機能主義と精神主義の二つの流れを持った。', ['kandinsky']),
    ('下剋上', '1467年応仁の乱が始まり、11年の京都戦乱で室町幕府は権威を失った。身分の低い者が上位者を倒す「下剋上」の時代が始まる。北条早雲(1432-1519)は素浪人から関東に覇を唱え、斎藤道三(1494-1556)は油商人から美濃国主へ、毛利元就(1497-1571)は安芸の一地方豪族から中国8ヶ国の太守に。織田信長(1534-1582)は尾張の二流大名からわずか20年で天下人へと駆け上がった。', ['oda_nobunaga']),
    ('桃山文化', '1573-1603年の安土桃山期は豪華絢爛と侘び寂びが同居した濃密な文化。千利休(1522-1591)は茶の湯を極限まで簡素化した侘茶を大成、秀吉に仕えたが1591年切腹を命じられた。狩野永徳(1543-1590)は「唐獅子図屏風」「洛中洛外図屏風」で金碧障壁画の頂点を極めた。南蛮貿易で鉄砲・時計・眼鏡・パン・カステラが伝来、フランシスコ・ザビエル(1506-1552)が1549年鹿児島上陸、キリシタンが一時40万人を超えた。', []),
    ('天下統一への道', '信長は1560年桶狭間で今川義元を討ち、1573年室町幕府を滅ぼし、楽市楽座・鉄砲隊(1575年長篠の戦い)で旧秩序を破壊したが、1582年本能寺で明智光秀に討たれた。豊臣秀吉(1537-1598)は同年山崎で光秀を破り、1590年小田原征伐で北条氏を滅ぼし天下統一。太閤検地・刀狩で兵農分離を固めた。徳川家康(1543-1616)は1600年関ヶ原で石田三成を破り、1603年江戸幕府を開いた。', ['oda_nobunaga', 'toyotomi_hideyoshi', 'tokugawa_ieyasu']),
    ('黒船ショック', '1853年6月3日、米国東インド艦隊司令長官マシュー・ペリーが黒船4隻(サスケハナ号、ミシシッピ号ほか)を率いて浦賀沖に現れた。蒸気船の威容と開国要求の国書に江戸は震撼。翌1854年3月、横浜で日米和親条約が締結され、下田・函館の開港が決まった。250年の鎖国体制が崩れ、国のかたちを根本から問い直す「幕末」が始まった。', []),
    ('志士たちの時代', '20〜30代の若者が国の運命を動かした。吉田松陰(1830-1859)は松下村塾で高杉晋作・伊藤博文・山県有朋らを育てたが、1859年安政の大獄で処刑された。坂本龍馬(1836-1867)は薩長同盟を仲介、1867年近江屋で暗殺される。西郷隆盛(1828-1877)・桂小五郎(1833-1877)が薩長同盟を結び倒幕を主導。新選組の近藤勇・土方歳三・沖田総司は京都で幕府側として戦った。', ['sakamoto_ryoma', 'saigo_takamori', 'kondo_isami', 'hijikata_toshizo', 'okita_soji']),
    ('維新の完成', '1867年10月、15代将軍徳川慶喜が大政奉還を上奏、260年の徳川幕府が幕を閉じた。12月、王政復古の大号令。1868年鳥羽伏見の戦いから戊辰戦争が勃発、会津戦争、函館五稜郭の戦いまで続いた(土方歳三は1869年函館で戦死)。明治新政府は五箇条の御誓文を発布、東京遷都、廃藩置県(1871)、徴兵制、地租改正——武士の時代は終わり、近代国家建設が始まる。', ['saigo_takamori', 'hijikata_toshizo']),
    ('国風文化', '894年、菅原道真の建議で遣唐使が廃止され、以後中国文化の影響を日本風に消化した「国風文化」が花開く。かな文字の発明(9世紀)が女性作家を可能にし、紫式部「源氏物語」(1008年頃)、清少納言「枕草子」(1000年頃)、藤原道綱母「蜻蛉日記」が生まれた。藤原氏による摂関政治が最盛期を迎え、藤原道長が1018年「この世をば わが世とぞ思う 望月の…」と歌った。', ['murasaki']),
    ('物語の誕生', '紫式部の「源氏物語」は54帖、300人以上の登場人物が絡む世界最古級の長編小説。光源氏の恋と権力と老い、「もののあはれ」の美意識が結晶化。清少納言の「枕草子」は「春はあけぼの」で始まる最初期の随筆。宮廷女房たちの筆が日本語の文学を可能にした。王朝和歌は「古今和歌集」(905、紀貫之らの編)で結晶。', ['murasaki']),
    ('元禄文化', '17世紀末〜18世紀初頭、上方(京都・大坂)を中心とした町人文化。井原西鶴(1642-1693)の「好色一代男」「日本永代蔵」で浮世草子が生まれ、近松門左衛門(1653-1725)の「曽根崎心中」(1703)は人形浄瑠璃の傑作。松尾芭蕉(1644-1694)の「奥の細道」(1689年の旅、1702年刊)は俳諧紀行文学の金字塔。「月日は百代の過客にして行きかふ年もまた旅人なり」。', ['basho']),
    ('化政文化', '19世紀初頭の文化・文政期、江戸を中心とした爛熟期。葛飾北斎「富嶽三十六景」(1831頃)と歌川広重「東海道五十三次」(1833-34)が浮世絵の頂点を極めた。曲亭馬琴(1767-1848)は28年かけて「南総里見八犬伝」(1814-1842完結)を書き、十返舎一九の「東海道中膝栗毛」、式亭三馬の「浮世風呂」——庶民を主役にした戯作文学が栄えた。小林一茶の俳句「雀の子 そこのけそこのけ お馬が通る」。', []),
    ('源氏物語', '紫式部(970年代-1019頃)が1008年頃、中宮彰子(藤原道長の娘)のもとに仕えながら執筆。54帖、90万字。光源氏の恋愛遍歴から宇治十帖の薫・匂宮まで、3世代・70年に及ぶ物語。「もののあはれ」の美意識、繊細な心理描写、四季の自然描写——世界文学史上の頂点の一つ。1000年後の今も読み継がれる。', ['murasaki']),
    ('枕草子と随筆', '清少納言(966頃-1025頃)は中宮定子(一条天皇の皇后)に仕えた女房。1000年頃に書かれた「枕草子」は日本最古級の随筆文学。「春はあけぼの」「うつくしきもの」「にくきもの」と自由な着想を連ねる。紫式部が「紫式部日記」で彼女を「したり顔にいみじう侍りける人」と評したのは有名。', []),
    ('神曲', 'ダンテ・アリギエーリ(1265-1321)はフィレンツェの名門に生まれたが、政争に敗れ1302年永久追放。放浪の中で「神曲」100歌を執筆、1321年ラヴェンナで完成直後に死去。地獄篇・煉獄篇・天国篇で魂の旅を描き、永遠の女性ベアトリーチェに導かれる。ラテン語ではなくトスカーナ方言で書いたことで、近代イタリア語文学の礎となった。', ['dante']),
    ('俗語文学の勝利', 'ペトラルカ(1304-1374)は1327年アヴィニョンの教会でラウラに出会い、以後40年間彼女への愛を歌った「カンツォニエーレ」366編のソネットを書いた。ボッカッチョ(1313-1375)は「デカメロン」(1353)でペスト禍のフィレンツェから逃れた10人が10日間100話を語る散文の金字塔。この「三冠詩人」がラテン語の権威に対抗する俗語文学を確立した。', []),
    ('シェイクスピア', 'シェイクスピア(1564-1616)はストラトフォード生まれ、ロンドンのグローブ座で37の戯曲と154のソネットを残した。「ハムレット」(1600頃)の「To be, or not to be」、四大悲劇「マクベス」「リア王」「オセロー」「ハムレット」、喜劇「真夏の夜の夢」「十二夜」、ロマンス劇「テンペスト」——人間のあらゆる感情が彼の筆で劇となった。1616年4月23日死去(セルバンテスと同日)。', ['shakespeare']),
    ('ドン・キホーテ', 'セルバンテス(1547-1616)はレパント海戦(1571)で左手を失い「レパントの隻手」と呼ばれた。アルジェで5年間捕囚の後、半生を牢獄で過ごしつつ1605年「ドン・キホーテ」前編、1615年後編を刊行。騎士道物語を読み過ぎて妄想に取り憑かれた老郷士の物語は、諷刺と哀愁が混じる近代小説の出発点となった。シェイクスピアと同日の1616年4月23日死去。', []),
    ('ファウスト', 'ゲーテ(1749-1832)は26歳でワイマール公国に招かれ、以後60年をこの小公国で過ごした。「ファウスト」第一部(1808完成)は悪魔メフィストフェレスと契約した老学者が若返り、純真な少女グレートヒェンを破滅させる物語。第二部(1831完成)は宇宙的スケールに広がり、「立ち止まれ、お前は美しい」と瞬間に言うとき魂は救われる。西洋文学の「もう一つの聖書」。', ['goethe']),
    ('若きウェルテル', '25歳のゲーテが失恋体験を4週間で書き上げた書簡体小説(1774)。画家志望の若者ウェルテルが婚約者のいるロッテに恋し、絶望して自殺する。発売後ヨーロッパ中で大ブームとなり、青年たちが「ウェルテル・ファッション」(青い燕尾服・黄色いチョッキ)を真似、自殺の連鎖まで起きた。「ウェルテル効果」という社会学用語の由来。', ['goethe']),
    ('悪の華', 'ボードレール(1821-1867)の「悪の華」(1857)は発売直後、風紀紊乱で裁判沙汰になり6編が削除命令を受けた。「私は美しい、おお死すべき人間たちよ、石の夢のように」。近代都市の憂鬱と退廃、アルコールと大麻の幻覚、娼婦とサタン——善悪の倒錯に詩の新たな主題を見出した。ランボー、ヴェルレーヌ、マラルメの象徴派へと受け継がれる。', []),
    ('ダンディズム', 'オスカー・ワイルド(1854-1900)は「ドリアン・グレイの肖像」(1890)で「芸術は無用だから美しい」という唯美主義を極限まで推し進めた。美しい青年の魂が絵の中で腐っていく寓話。1895年同性愛の罪で2年の重労働刑、名声と富を一挙に失う。出獄後パリで客死、最後の言葉は「この壁紙か私か、どちらかが出ていかねば」と伝わる。', ['oscar_wilde']),
    ('漱石の苦悩', '夏目漱石(1867-1916)は1900年英国留学で神経衰弱を病み、帰国後「吾輩は猫である」(1905)でユーモラスに文壇登場。東大教授を辞し朝日新聞に入って職業作家となる。「坊っちゃん」「三四郎」「それから」「門」「こころ」(1914)——近代人の自我と孤独を掘り下げた。持病の胃潰瘍で1916年49歳で没、「則天去私」の境地を最後に求めていた。', ['soseki']),
    ('川端・三島', '川端康成(1899-1972)は「伊豆の踊子」(1926)、「雪国」(1937-48)、「千羽鶴」「山の音」で日本美を結晶化、1968年日本人初のノーベル文学賞。受賞講演「美しい日本の私」。三島由紀夫(1925-1970)は「金閣寺」(1956)、「憂国」、四部作「豊饒の海」を完成させた日の1970年11月25日、自衛隊市ヶ谷駐屯地で憲法改正を訴え割腹自殺。川端も1972年にガス自殺した。', ['kawabata', 'mishima_yukio']),
    ('実存と不条理', 'カフカ(1883-1924)の「変身」(1915)「ある朝、グレーゴル・ザムザは目覚めたとき、一匹の巨大な毒虫に変わっていた」。長編「審判」「城」は死後出版された。カミュ(1913-1960)「異邦人」(1942)の「ママンが死んだ」、サルトル「嘔吐」(1938)、ベケット「ゴドーを待ちながら」(1953)——20世紀の不条理が小説と演劇の主題となった。', ['kafka']),
    ('意識の流れ', 'ジョイス(1882-1941)「ユリシーズ」(1922)は1904年6月16日ダブリンの1日を現代のオデュッセイアとして700ページで描く。プルースト(1871-1922)「失われた時を求めて」(1913-27)は全7巻・3000ページ以上、マドレーヌ菓子一口から始まる記憶の宇宙。ヴァージニア・ウルフ「ダロウェイ夫人」(1925)、フォークナー「響きと怒り」(1929)——意識の流れが小説の新技法となった。', []),
    ('地動説の勝利', '1543年、コペルニクス(1473-1543)が「天球の回転について」を死の床で出版し地動説を提唱。ガリレオ(1564-1642)は1609年自作望遠鏡で木星の4衛星を発見し地動説の証拠を得たが、1633年ローマ教皇庁の異端審問で屈服「それでも地球は動いている」。ケプラー(1571-1630)はティコ・ブラーエの観測データから1609-1619年に惑星運動の3法則を発見、楕円軌道説で天体力学の基礎を築いた。', ['galileo', 'kepler']),
    ('ニュートンの総合', 'アイザック・ニュートン(1642-1727)はケンブリッジ大学でペスト流行中の1665-1666年「奇跡の年」に微積分、光学、万有引力の着想を得た。1687年「プリンキピア(自然哲学の数学的諸原理)」で運動の3法則と万有引力の法則を体系化、天体と地上の物体が同じ法則に従うと示した。科学革命の完成。1704年「光学」でプリズムと色の研究を発表、晩年は錬金術と聖書の研究に没頭した。', ['newton']),
    ('進化論の衝撃', 'ダーウィン(1809-1882)は1831-1836年ビーグル号で5年間世界周航。ガラパゴス諸島のフィンチ(鳥)の嘴の違いが自然選択の着想を与えた。帰国後20年間熟慮し、ウォレスの同じ着想に触発されて1859年「種の起源」出版。「神の創造」ではなく自然選択で生物の多様性を説明した。メンデル(1822-1884)は修道院で1865年エンドウ豆の遺伝法則を発見したが34年間無視された。', ['darwin']),
    ('電気の時代', 'ファラデー(1791-1867)が1831年電磁誘導を発見、マクスウェル(1831-1879)が1864年電磁方程式で体系化。エジソン(1847-1931)は1879年実用的な白熱電球、1877年蓄音機、1891年活動写真キネトスコープなど生涯1093件の特許を取得。テスラ(1856-1943)は交流電力システムを実用化、エジソンの直流との「電流戦争」に勝利、1893年シカゴ万博を交流で照らした。', ['edison', 'tesla']),
    ('相対性理論', '1905年「奇跡の年」、スイス特許局職員アインシュタイン(1879-1955)は4本の革命的論文を発表：光量子仮説、ブラウン運動、特殊相対性理論、E=mc²。1915年一般相対性理論で重力を時空の歪みとして記述。1919年エディントンの日食観測で光の湾曲が実証され世界的英雄に。1921年ノーベル物理学賞。1933年ナチスから逃れ米国へ移住、1939年ルーズベルトへの手紙が原爆開発の端緒となった。', ['einstein']),
    ('量子力学', '1900年プランクが黒体放射で量子仮説を提唱、1913年ボーアが原子模型を作り、1925年ハイゼンベルクが行列力学、1926年シュレーディンガーが波動力学。1927年ハイゼンベルクの不確定性原理——ミクロの世界は確率に支配される。同年ソルヴェイ会議でアインシュタイン「神はサイコロを振らない」、ボーア「誰が神に指示するのか」の歴史的論争。湯川秀樹(1907-1981)は1935年中間子論を提唱、1949年日本人初のノーベル物理学賞を受賞した。', ['einstein', 'yukawa_hideki']),
    ('無意識の発見', 'フロイト(1856-1939)は1900年「夢判断」で無意識の存在を提唱。夢は願望の充足、言い間違いや神経症の症状は抑圧された衝動の噴出。1923年「自我とエス」でエス・自我・超自我の心の構造理論を完成。1938年ナチスからロンドンへ亡命、翌年そこで没。心理学・文学・美術・映画への影響は計り知れない。弟子ユングは集合的無意識論で師と袂を分かった。', ['freud']),
    ('計算と知能', 'アラン・チューリング(1912-1954)は1936年論文「計算可能数について」で汎用計算機械(チューリングマシン)の数学的概念を提示、現代コンピュータの基礎を築いた。第二次大戦中はブレッチリー・パークでナチスの暗号機エニグマを解読、戦争を2年短縮したと言われる。1950年論文「機械は考えるか？」でチューリング・テストを提案、人工知能研究の原点。1954年同性愛のためホルモン療法を強制された2年後、リンゴをかじって自殺した。享年41。', ['turing']),
    ('近代科学の輸入', '明治政府はお雇い外国人(モース、ベルツ、ダイアーら)を招き、優秀な留学生を送り出した。北里柴三郎(1853-1931)はドイツでコッホに師事、1889年世界初の破傷風菌純粋培養に成功、1894年香港でペスト菌を発見。野口英世(1876-1928)は黄熱病研究中にアフリカで殉職。1917年理化学研究所が設立され、長岡半太郎、仁科芳雄らが日本の近代物理を育てた。', []),
    ('ノーベル賞の時代', '1949年、湯川秀樹(1907-1981)が中間子論で日本人初のノーベル物理学賞。敗戦から4年、焦土の日本に希望の光を射した。1965年朝永振一郎が量子電磁力学の繰り込み理論で受賞。1981年福井謙一(化学)、1987年利根川進(医学生理学)、2002年小柴昌俊(物理・ニュートリノ検出)、田中耕一(化学)、2012年山中伸弥(iPS細胞)——戦後日本の基礎研究の成果が次々と実を結んだ。', ['yukawa_hideki']),
]

count = 0
for title, body, people in rewrites:
    pattern = r"(\{ title: '" + re.escape(title) + r"', period: '[^']*', )body: '[^']*'( \})"
    # escape single quotes in body for JS string
    body_esc = body.replace("\\", "\\\\").replace("'", "\\'")
    people_str = ''
    if people:
        people_str = ", people: [" + ", ".join("'" + p + "'" for p in people) + "]"
    replacement = r"\1body: '" + body_esc + r"'" + people_str + r"\2"
    new_content, n = re.subn(pattern, replacement, content)
    if n > 0:
        content = new_content
        count += n
    else:
        print('NOT FOUND:', title)

with open(path, 'w', encoding='utf-8') as f:
    f.write(content)
print('Rewrote', count, 'sections')
